BASE_DIR='/Users/samrosa/DEV/3D/Grade8_FutureDesigner'
lessons_data = [{'module': '算法美学与高阶曲面', 'id': 17, 'title': '生命轨迹 - 扫掠 (Sweep) 生成法', 'desc': '学习顺着非直线的路径铺设实体。', 'keywords': 'Sweep, Path, Guide curve', 'tips': '- 提醒扫掠必须有两个独立的草图：横截面 (Profile) 和路径 (Path)。\n- 这两者必须在空间坐标中垂直或交叉。', 's1': {'title': '管道的秘密', 'point': '排气管、花瓶提手、电线电缆，它们都不是直的，挤除无法完成！', 'interactive': '观察一个扭曲的杯子手柄是如何成型的。'}, 's2': {'title': '创造双重维度', 'point': '使用扫掠让截面魔法般沿着一条线前行并形成闭合物。', 'op': '切换到底视图画管口尺寸 -> 切换到侧视图(垂直于底视)画出蛇形的导流线 -> 选择 Sweep 工具将它们联结。', 'warning': '曲线的弯管半径必须大于管口的半径，否则会发生自己穿透自己的错误！'}, 's3': {'title': '支撑算法中的空洞', 'point': '复杂管形内部是否排布支撑？', 'settings': '仅开启『从构建板上接触(Touch Buildplate Only)』而不是『所有位置(Everywhere)』。', 'physics': '管壁内部强行塞入支撑很难拆除，尽量依赖桥接，必须让打印机理解空洞结构不加保护。'}, 's4': {'title': '弯管流体测试', 'tolerance': '验证水流通过管道时没有泄漏（打印时增加墙线层数 Wall loops 以防水）。'}}, {'module': '算法美学与高阶曲面', 'id': 18, 'title': '形态变异 - 放样 (Loft) 创造器', 'desc': '连接不同截面的过渡形态设计。', 'keywords': 'Loft, 导线, 渐变表面', 'tips': '- 放样至少需要两个处于平行的截面草图。\n- 添加引导线(Guide Rail)才能决定腰部的曲率。', 's1': {'title': '从圆变方的魔法', 'point': '吹风机出风口、船体外壳、各类工业变径接头，都在用渐变变形。', 'interactive': '展示一个上端方形、下端圆形的异形过渡件。'}, 's2': {'title': '平行面叠加', 'point': '如何在空中凭空创建一个面？必须利用构造平面(Construction Plane)。', 'op': '建立底面草图(方) -> 向上偏移创造参考面 -> 在参考面上画(圆) -> 执行 Loft 联结。', 'warning': '没有匹配定点会造成放样曲面扭曲如麻花，需要手动拨动对齐定点(Mapping point)。'}, 's3': {'title': '流线表面的层纹折射', 'point': '光滑过渡带来的切片层纹放大效应(', 'settings': '开启自适应层高 (Adaptive layer height)。', 'physics': '当坡度越平缓，哪怕 Z 轴仅仅移动了一点点，投影到 X/Y 面上的位移都巨大，会导致阶梯纹。自适应可以压低层高来打磨。'}, 's4': {'title': '手感握持', 'tolerance': '打印一个放样得出的自定义鼠标或者手柄壳体验人机工程贴合度。'}}, {'module': '算法美学与高阶曲面', 'id': 19, 'title': '秩序阵列 - 参数化带来的克隆大军', 'desc': '以一化万的工业矩阵逻辑。', 'keywords': 'Array, Pattern, 组件复用', 'tips': '- 阵列不仅仅是位置变化，还能通过距离公式设置非线性排列。\n- 草图阵列不如实体阵列稳定。', 's1': {'title': '繁复的秩序美', 'point': '机箱上的100个散热孔难道要画100次草图？', 'interactive': '展示一把梳子，数一数上面的齿。'}, 's2': {'title': '矩阵展开', 'point': '线性和环形规律的终极表达。', 'op': '画一个基本孔(或凸钉)实体 -> 采用 Linear Pattern 输入X与Y方向的个数与间距。', 'warning': '大批量阵列极为消耗 CPU 算力。尽量在模型制作的最后一步才做阵列。'}, 's3': {'title': '回抽策略 (Retraction)', 'point': '一百个孔洞意味着喷头要跨越无数次虚空！必须要锁住熔解的塑料。', 'settings': '调校回抽长度(Retraction length)至 0.8mm (直驱) 避免拉丝海。', 'physics': '管内负压机制：挤出机齿轮反转，将热管内的压力瞬间卸掉，阻止熔丝滴落。'}, 's4': {'title': '散热孔径排查', 'tolerance': '用卡尺和钻头测量打出的孔阵列中是否存在因积瘤变小的残次孔。'}}, {'module': '算法美学与高阶曲面', 'id': 20, 'title': '拓扑回环 - 回转 (Revolve) 与莫比乌斯', 'desc': '学习车床加工思维以及基础拓扑结构体。', 'keywords': 'Revolve, 旋转体, 拓扑', 'tips': '- 旋转必须有且只有一个中心轴线。\n- 剖面不要越过自身中心轴线，否则实体互相干涉。', 's1': {'title': '车床的逻辑', 'point': '高脚杯、轮胎、象棋子，它们的共同点是什么？只要转起来就是它！', 'interactive': '转动一枚硬币形成虚影球体。'}, 's2': {'title': '一半即全部', 'point': '不再画俯视图，直接切开它画正侧部的『半片剖面』。', 'op': '建立一条中心竖线 -> 画高脚杯左半边截面 -> 选择 Revolve 绕纵轴 360 度转圈。', 'warning': '中心线处必须是一条直线闭合点，不能有零星空隙，不然回转会产生带贯穿洞的怪异空心体！'}, 's3': {'title': '周长分段(Resolution)', 'point': '计算机里没有绝对的圆，它只是由100万个短边拼成的多边形。', 'settings': '导出 3MF 或 STL 时调整三角面精度。', 'physics': '低模型细节(Low poly)导出并在切片软件观察。切片软件通过 G02/G03 圆弧插补指令来顺滑边缘或者依赖模型本身的顶点。'}, 's4': {'title': '壁厚共振', 'tolerance': '用较脆的高温耗材打极薄杯子，轻敲听其发声，探测层间物理附着力带来的声学反馈。'}}, {'module': '算法美学与高阶曲面', 'id': 21, 'title': '仿生侵染 - AI to 3D 的生成思维', 'desc': '前沿课：AI图片转深度的工具流初探。', 'keywords': 'Prompt, Displacement, 仿生几何', 'tips': '- 可以用 Midjourney/Stable Diffusion 产生灰度和黑白纹理。\n- 把图片转成 SVG 后导入往往更适合新手。', 's1': {'title': '超自然构造', 'point': '有些蜂巢结构和珊瑚骨架完全靠手动拉伸几乎无法实现。', 'interactive': '展示生成式设计的航空飞机支架以及 AI 多边形艺术品。'}, 's2': {'title': '高度贴图映射 (Displacement)', 'point': '像素也有厚度，黑色代表低凹，白色代表凸起。', 'op': '指导将 AI 生成的维诺(Voronoi)灰阶图片转出 SVG 并投射贴面形成实体网络。', 'warning': '过高的面数转换会直接让软件未响应崩溃，务必对图片进行简化处理。'}, 's3': {'title': '自适应填充 (Lightning)', 'point': '面对如此庞大复杂的外部结构，内部填充采用什么策略最快？', 'settings': '开启闪电(Lightning)或者自适应填充。', 'physics': '这种填充像树根一样只长在高处支撑的下面，在底层呈现空心，极大节省材料。'}, 's4': {'title': '镂空通透率', 'tolerance': '透光查看仿生小孔边缘是否存在支撑残留。'}}, {'module': '算法美学与高阶曲面', 'id': 22, 'title': '表面附着 - 投影(Project)映射工艺', 'desc': '在曲面上进行平面草图雕刻的高能技法。', 'keywords': 'Project, 曲面雕刻, 表面融合', 'tips': '- Shapr3D 的 Project 到曲面功能是高级工程的杀手锏。\n- 被投射表面必须是可以连续展开的。', 's1': {'title': '变形的徽章', 'point': '想在弧形的胸甲或头盔上印一个巨大的数字铭牌，该怎么走形？', 'interactive': '让学生想想如果在地球仪上用笔画一个直直的十字架，会发生什么。'}, 's2': {'title': '空间投射(Project to Surface)', 'point': '悬浮的二维画作击穿三维屏障印制。', 'op': '在模型旁平行创建一个基准面并画草图 -> 选用 Project (投影) -> 指定曲面为投射底板。', 'warning': '被投射的面如果超越了平面的正投影范围会造成变形甚至投影丢失！'}, 's3': {'title': '曲面换色的悲剧', 'point': '在一个带有弧度的面上使用 AMS 多色打印会有不同寻常的问题。', 'settings': '观察切片机里的废料冲刷块(Prime tower)，在打印多颜色曲面时巨大的换色时间开销。', 'physics': '每个层的 X/Y 会呈现颜色的台阶抖动，非垂直字体的双色表现往往差强人意。'}, 's4': {'title': '贴合公差', 'tolerance': '使用 1mm 的投射突出，配合切片厚度 0.2mm 是否恰好出现 5 层完整换色楼梯？'}}, {'module': '算法美学与高阶曲面', 'id': 23, 'title': '镜像对立 - 中心轴对称法则', 'desc': '省下一半精力的超级工业法门。', 'keywords': 'Mirror, 对称世界, 原点平面', 'tips': '- 尽早确定是对『草图』做对称还是对『实体』做对称。\n- 对称面的选择是核心，务必围绕原点面！', 's1': {'title': '生物与宇宙的规则', 'point': '为什么所有跑车和飞船都是左右对称的？如何设计左机翼后直接克隆出右机翼...', 'interactive': '切半个苹果和一整辆跑车的设计草图。'}, 's2': {'title': '镜像实体的融合', 'point': '只建立一半细节最极端的赛博装甲，然后跨越中线魔法克隆！', 'op': '选择半边复杂的成型实体组件 -> 启动 Mirror 工具 -> 点击中心大平截面为镜子。', 'warning': '如果模型哪怕偏离中心基准面 0.1 毫米，镜像后中间就会产生毁灭性的缝隙或重叠！'}, 's3': {'title': '左右热不均', 'point': '庞大且对称的模型为何时常两半会有应力收缩不一致导致开裂？', 'settings': '关注散热风扇的方向设定并加入箱体环境保温。', 'physics': '不对称的气流(左侧冷却系统吹向模型与右侧)会让热胀冷缩产生不均衡微小误差，翘边即从最冷端起。'}, 's4': {'title': '对称缝隙验定', 'tolerance': '用肉眼观察大平面正中是否因为未粘合紧密留下发光裂纹。'}}, {'module': '算法美学与高阶曲面', 'id': 24, 'title': '工业修补 - 破损件数字重生法', 'desc': '学习运用逆向工程思维在实物残缺件上获取测量及建模数据，制造修复补丁卡扣。', 'keywords': 'Repair, 逆向思维, 生活骇客', 'tips': '- 这是非常开放的一课，可以准备断掉的抽屉把手或耳机挂架。\n- 拍照做底图是个好习惯。', 's1': {'title': '物品不弃', 'point': '不甘心丢掉的好东西，只差了一个塑料转轴和卡扣！', 'interactive': '展示被完美修复延长寿命的各种生活小电器外壳。'}, 's2': {'title': '相片映射测绘制', 'point': '使用标尺和破碎残骸做底版图片投射描摹！', 'op': '导入断裂部件顶视图照片 -> 根据比例进行缩放校准 -> 在照片上原样描画出缺失轮廓的大致曲线。', 'warning': '手机镜头的畸变会导致图片四周不准！照片必须以最中心部位进行拍摄。'}, 's3': {'title': '不同耗材强度对抗', 'point': '仅仅打印一个 PLA 代替会发现用不了一星期就再次断裂！', 'settings': '了解 PETG, ABS 与 TPU (弹性)的不同材料配置和预设切换（重点是热床温度要提高）。', 'physics': 'PLA 太脆，PETG 韧性好，ABS 耐高温，材料物理直接决定修补寿命。'}, 's4': {'title': '修补兼容性', 'tolerance': '用 0.1-0.2 mm 过盈配合，加点极客胶水(快干胶)，完成装配！'}}, {'module': '运动机制与未来都市', 'id': 25, 'title': '一体成型(一) - 魔法合页与折叠空间', 'desc': '接触神级技巧：免组装直接打出的活动关节 (Print-in-place)。', 'keywords': 'Print-in-place, Hinge, 活动轴承', 'tips': '- 重点分析转轴与外壳间的锥形圆缺或圆柱缝隙(间隙至少0.3)。\n- 底层切忌出现大象脚。', 's1': {'title': '不需要螺丝的机器', 'point': '从零开始认识什么是 Print In Place(打印即玩)。打破只能打印死板硬物的传统认知。', 'interactive': '发给学生刚打印好但是稍微用点力就能掰开旋转的折叠霸王龙。'}, 's2': {'title': '微距圆锥法', 'point': '如何设计不会在打印中『黏成一块』的内部轴承销钉？', 'op': '使用并向里嵌入两个尖对尖相差 0.3mm 缝隙的圆锥转子。', 'warning': '接触面的缝隙如果被任何斜面的支撑给填满，就永远拧不开了，绝对要禁止支撑长进内部零件！'}, 's3': {'title': '第一层的毁灭性张力', 'point': '最致命的在于底部接触平面的第一层！', 'settings': '调节『象脚补偿 (Elephant foot compensation)』为 0.15mm。', 'physics': '如果底部没有收缩补偿，第一层的塑料因被压扁向外溢出，瞬间就会把你留的那 0.3mm 运动间隙焊死填平！'}, 's4': {'title': '破冰扭矩', 'tolerance': '出炉后需要用力“咔咔”扭一下破冰，要求用力能打开即是不败神话。'}}, {'module': '运动机制与未来都市', 'id': 26, 'title': '一体成型(二) - 陀螺环与联动齿轮', 'desc': '多向运动嵌套打印法与万向节。真正的工程魔法。', 'keywords': 'Gymbal, Gear, 动力传递', 'tips': '- 对倒角的需求极高，所有运动间隙边缘必须做 Chamfer 斜面打通以防堆料。\n- 这节课建议直接修改和探索半成品文件。', 's1': {'title': '三轴稳定的秘密', 'point': '什么是万向节底座（Gimbal）？', 'interactive': '展示一个四环嵌套并在空中随意多角度转动的环阵。'}, 's2': {'title': 'V字槽间隙解剖', 'point': '不再使用平面配合，利用 45度斜边构建自我居中效应。', 'op': '画出圆环截面上的>型凹槽，与隔壁环的<凸起保留缝隙，接着旋转生成(Revolve)。', 'warning': '这必须是纯闭环的空隙走廓(V-groove)，切不可画成90度导致水平层层相切贴死。'}, 's3': {'title': '冷却的竞速战', 'point': '对于狭小缝隙内的圆环，打印过快会因为上一层没冷透就被下一层黏住。', 'settings': '切片软件中修改 Minimum Layer time (最低层时间)为 8秒以保障充分冷却！', 'physics': '越过玻璃态转化点前，两层PLA表面其实极高粘度，必须冷到室温态才能让两者保持平行分离。'}, 's4': {'title': '万向自旋校验', 'tolerance': '拨动内外环，检验是否每个维度都彻底解开枷锁自由摆动。'}}, {'module': '运动机制与未来都市', 'id': 27, 'title': 'Neo-Metropolis - 未来都市项目启航', 'desc': '团队宏图沙盘。建立共同城市地块的世界观分配规则和接口协议。', 'keywords': '沙盘协议, 公用接口, 规范化定标', 'tips': '- 教师扮演总规划师，强调接口标准是团队协作基础。\n- 建议引入 40x40mm 六角拼接或者正方形作为所有人的标准件地台。', 's1': {'title': '标准化接口的世界法则', 'point': '为何乐高的任何两块砖都能拼上？因为有统一严密的标准！', 'interactive': '分发每人发一块相同的空白六边形底座标准板（实物与配套数字文件）。'}, 's2': {'title': '强制坐标空间', 'point': '团队里的每一个人必须在系统预先给定好的尺寸框里设计。', 'op': '导入官方 Standard_Tile.3mf，锁定不能移动其 XY 面标高，在上方延伸大楼结构。', 'warning': '绝对不可以私自修改标准接口上的哪怕 0.1 毫米卡口！否则你的楼装不上地球沙盘！'}, 's3': {'title': '超大工程的版本管理', 'point': '几十件拼合的规划。提前预览合并打印件的方法。', 'settings': '导入多个不同的项目到同一个切片软件进行体积检视干涉区。', 'physics': '预排布可以看见城市的天际线高高低低错落有致，并核对光照投影。'}, 's4': {'title': '沙盘兼容测试', 'tolerance': '用卡尺实地测量打印出台地基尺寸是否精准符合总局发布 40.0mm 尺度。'}}, {'module': '运动机制与未来都市', 'id': 28, 'title': '赛博基建 - 模块化单元开发', 'desc': '进行城市各自认领功能建筑的设计，加入能量槽与高塔特征。', 'keywords': '模块化, Sub-assembly, 城市风光', 'tips': '- 鼓励大家使用不对称和斜坡建筑，不要全部设计成方块楼。\n- 加入天桥横跨拼接概念。\n- 灵活运用 Pattern 阵列制造千篇一律的密集住宅窗户。', 's1': {'title': '你定义了哪种文明？', 'point': '太空农业工厂、核磁能中继塔或是高空磁浮轨交枢纽？', 'interactive': '大屏幕分享赛博朋克大作和微缩未来废土高楼的参考图。'}, 's2': {'title': '高层复用设计', 'point': '组合之前所学：扫掠出管道桥梁、阵列出高楼外表面。', 'op': '建立基本大楼主体矩形阵列后，在四周叠加并环绕走廊与停机坪面板。', 'warning': '设计中不要加入太细太长的“发射天线”，极容易在打印中成为拉丝或者折断断剑点。'}, 's3': {'title': '城市重力分布规划', 'point': '切片设定时，上大下小的建筑物如何稳固在地基上不倒？', 'settings': '在切片软件利用变层厚，基座使用较高的填充密度重心下移，楼顶采用5%极低填充减轻负荷。', 'physics': '力矩偏向和底面侧翻。大楼风载也必须考虑进高层摇摆物理之中。'}, 's4': {'title': '立面效果查验', 'tolerance': '展示并利用灯光照射打印建筑楼面，检查细节呈现是否被拉出大象腿层纹隐患。'}}, {'module': '运动机制与未来都市', 'id': 29, 'title': '光影引擎 - 镂空与内置光源设计', 'desc': '在数字城市中嵌入电路的走线槽，打穿真实光电。', 'keywords': 'Led-slot, 布线穿云, 透光技术', 'tips': '- 预留 5mm 直径管道供 LED 灯带或电源线穿梭。\n- 半透明/白色 PLA 的透光最佳壁厚设定为 0.8 至 1.2 mm 之间。', 's1': {'title': '点亮不夜城', 'point': '真正的沙盘在光照下才能出现赛博朋克的精髓光污染！', 'interactive': '给一栋白色的楼体暗箱内点亮小黄灯泡，立刻化身未来发光大楼。'}, 's2': {'title': '负零件内引桥(管道布置)', 'point': '必须为穿线留下空洞通道，这就需要从底部挖管到楼顶！', 'op': '使用大 Sweep 扫掠命令沿着墙角走线画出隐蔽内管，与底座和中间层做布尔切割。 ', 'warning': '通道不可以是折型直角转弯，否则电线绝对穿不过去，务必将走线洞内部导很大的 Fillet 曲线边！'}, 's3': {'title': '光源扩散学', 'point': '想让一整面墙发出雾蒙蒙的光，而不是看到内部刺眼的 LED 颗粒本身？', 'settings': '控制墙层厚等于 3 层线宽（3 top layers），改变填充层数使光向四周产生散射。', 'physics': '塑料材料由于是半透明聚合物具有一定的光衰竭性与全反射效应，这是工业毛玻璃的奥义。'}, 's4': {'title': '透光度检验', 'tolerance': '置入小灯珠测试透光亮度及线材是否能顺利穿引进入预设引线道。'}}, {'module': '运动机制与未来都市', 'id': 30, 'title': '工程联结 - 磁吸与卡扣的高能运用', 'desc': '引入外部工业小五金配件的复合结合法，真正将打印件变成工业品。', 'keywords': 'Magnet Insert, 卡榫, 五金配合', 'tips': '- 准备一堆真实圆柱铁硼磁铁(常见公差5x2mm)。\n- 确保测量准了磁铁公差再挖洞。', 's1': {'title': '不可思议的模块魔法', 'point': '不仅能拼合，还能随时随地吸附拆解！', 'interactive': '拿出两个完美利用磁铁吸合在一起的高档连接件啪嗒声脆响。'}, 's2': {'title': '底座吸附盲洞开孔', 'point': '为我们的标准件基座和顶配外设增加盲孔仓室预留以置入磁铁。', 'op': '在底板内面画出直径 5.1(扩大0.1公差) 深度 2.2 的圆槽后进行拉伸切割闭合。', 'warning': '磁铁正负极绝对不能在中途混淆，否则整个地基只能报废排斥了！必须标注南北极方向。'}, 's3': {'title': '隐形磁铁高级法', 'point': '把磁铁永久封装进 3D 打印件里的黑魔法操作！', 'settings': '增加 `Pause at Height`。在刚刚切好磁孔盖子前的那一层暂停机器，走过去把磁吸放进去，再继续封顶遮蔽！', 'physics': '强力磁胶封装在无氧无破口的闭室中，可历经百年不生锈不消磁。'}, 's4': {'title': '悬挂拉力挑战', 'tolerance': '两个带磁扣的组分连接后承受 100g 负载是否脱开。'}}, {'module': '运动机制与未来都市', 'id': 31, 'title': '批量列印 - 满盘打印的风险管控', 'desc': '为了明天的终极大展出，进行通宵的极速大规模切片作业规划。', 'keywords': 'GCode, 风险分散, 批处理', 'tips': '- 这是纯技术课也是总结课。要讲明白墨菲定律在 3D 打印上的显现。\n- 如何挽救打印了一半的进度。', 's1': {'title': '灾难的前夜', 'point': '当你睡觉时发生了断丝堵头并制造了一整盘意大利面？不可原谅。', 'interactive': '如何使用 Bambu 的 AI 小面条检测(Spaghetti detection)，它是怎样通过云相机识别废件的？'}, 's2': {'title': '排班大师', 'point': '在大型工程中如何对时间及材料损耗计算，通过合理布局提升打印热床利用率且规避塔群效应。 ', 'op': '进行海量模块整合摆放测试，修改模型外倾斜角以规避支撑堆叠导致时间过长。', 'warning': '避免高个子和矮个子模型混满一整盘！因为会导致打印矮个子结束后的漫长数小时，喷头在空荡区拉丝极长跳跃去打高个子尖端。'}, 's3': {'title': '模型拯救法', 'point': '大楼因为停电断在了一半？别扔，教你切片下沉救法！', 'settings': '在切片软件选中半残件，Z轴向热床下移动至刚好断裂的 Z 面高，切片成新楼顶然后粘合！', 'physics': '坐标系的相对参照法与实体接壤融合缝补法则。'}, 's4': {'title': '出片检测', 'tolerance': '清点所有 32 份模块化套件，检验各拼接卡扣间隙。'}}, {'module': '运动机制与未来都市', 'id': 32, 'title': '赛博路演 - 最终沙盘整合与展示', 'desc': '组装巨型都市，连接所有能源线，发布会演示全流程架构。', 'keywords': 'Capstone, Presentation, 结构评审', 'tips': '- 准备一块大黑色板子用来拼装，现场熄灯效果拔群。\n- 每一名学生负责一段自我设计路演。\n- 为学生颁发《未来设计师：数字硬件极客初级证明》。', 's1': {'title': '从零到世界', 'point': '一个月前只有点线面的枯燥数学几何，如今汇聚成了一座实体新星！', 'interactive': '学生动手把自己专属的大楼和城市组件插在总基座规划网格中。'}, 's2': {'title': '全景解剖展示', 'point': '回顾从约束、公差到布尔极客逻辑，大家是如何解开工业难题的。', 'op': '连通内部 LED 网络走线并完成光效启动环节，检验团队通电通道畅通。', 'warning': '展示时注意各线路连通处的绝缘胶布，勿出现走水短路情况！'}, 's3': {'title': '最终总结篇章', 'point': '我们是在用光与塑料制造梦想。', 'settings': '无特殊切片，因为这是最终物理复核和展览阶段与复审时间。', 'physics': '整个光与影子的矩阵是靠参数控制、精准机械定位及耗材沉积凝固三合一的奇迹。'}, 's4': {'title': '闭幕验收', 'tolerance': '团队成功通电、大沙盘完整展现无脱缝摇晃则为完全验收通过！'}}]

